enum SourceReader {
    Read(Box<dyn Read + Send + 'static>),
    File(File),
    Child(Box<ChildProcess>),
    Closed,
}

impl SourceReader {
    fn finish(&mut self) -> Result<(), ShellError> {
        if !matches!(self, SourceReader::Child(_)) {
            return Ok(());
        }

        let SourceReader::Child(child) = std::mem::replace(self, SourceReader::Closed) else {
            unreachable!()
        };
        child.wait()
    }
}

impl Read for SourceReader {
    fn read(&mut self, buf: &mut [u8]) -> io::Result<usize> {
        match self {
            SourceReader::Read(reader) => reader.read(buf),
            SourceReader::File(file) => file.read(buf),
            SourceReader::Child(child) => child
                .stdout
                .as_mut()
                .map_or(Ok(0), |stdout| stdout.read(buf)),
            SourceReader::Closed => Ok(0),
        }
    }
}

